class Stack<T> {
    private val items = mutableListOf<T>()

    fun push(item: T) { items.add(item) }
    fun pop(): T? = items.removeLastOrNull()
    val size: Int get() = items.size
}

fun <T> printRepeated(item: T, times: Int) {
    repeat(times) { println(item) }
}

fun main() {
    val stack = Stack<Int>()
    stack.push(1)
    stack.push(2)
    stack.push(3)

    println(stack.pop())  // 3
    println(stack.pop())  // 2

    printRepeated("Kotlin", 3)
}
